import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import { loginSuccess } from './store/authSlice';
import { authAPI } from './api';  // ← ИМПОРТИРУЙТЕ API!

function LoginPage({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);

  const dispatch = useDispatch();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      let result;

      if (isRegistering) {
        // Используйте authAPI.register!
        result = await authAPI.register(username, password);
      } else {
        // Используйте authAPI.login!
        result = await authAPI.login(username, password);
      }

      if (result.success) {
        // authAPI уже сохраняет в localStorage!
        // token и username уже сохранены в localStorage через api.js

        // Диспатчим успешный логин в Redux
        dispatch(loginSuccess({
          token: result.data.token,
          username: result.data.username || username
        }));

        // Вызываем callback
        onLogin();
      } else {
        setError(result.message ||
          (isRegistering ? 'Ошибка регистрации' : 'Ошибка авторизации'));
      }
    } catch (err) {
      console.error('Login error:', err);
      setError('Ошибка соединения с сервером');
    } finally {
      setLoading(false);
    }
  };

  // ... остальной код без изменений
  return (
    <div className="login-container">
      <div className="login-box">
        <h1>Лабораторная работа №2</h1>
        <h2>Проверка попадания точки в область</h2>

        <div className="student-info">
          <p><strong>ФИО:</strong> Ваше ФИО</p>
          <p><strong>Группа:</strong> Ваша группа</p>
          <p><strong>Вариант:</strong> Ваш вариант</p>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          <h3>{isRegistering ? 'Регистрация' : 'Вход в систему'}</h3>

          <div className="form-group">
            <label htmlFor="username">Логин:</label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
              disabled={loading}
              placeholder="Введите логин"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Пароль:</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={loading}
              placeholder="Введите пароль"
            />
          </div>

          {error && <div className="error-message">{error}</div>}

          <button
            type="submit"
            className="login-btn"
            disabled={loading}
          >
            {loading ? 'Обработка...' : (isRegistering ? 'Зарегистрироваться' : 'Войти')}
          </button>

          <button
            type="button"
            className="toggle-btn"
            onClick={() => setIsRegistering(!isRegistering)}
            disabled={loading}
          >
            {isRegistering ? 'Уже есть аккаунт? Войти' : 'Нет аккаунта? Зарегистрироваться'}
          </button>

          <div className="test-credentials">
            <p>Для тестирования можно использовать:</p>
            <p>admin / admin123</p>
            <p>Или регистрация</p>
          </div>
        </form>
      </div>
    </div>
  );
}

export default LoginPage;
